function parseConfig(raw) {
  const lines = raw.split('\n');
  const result = {};
  for (const line of lines) {
    const [key, val] = line.split('=');
    if (key && val) result[key.trim()] = val.trim();
  }
  return result;
}
module.exports = { parseConfig };

